import{_ as a,c as r,o,a5 as l}from"./chunks/framework.Dtwt352Q.js";const g=JSON.parse('{"title":"隐私政策","description":"OpenCode 中文教程网站的隐私政策，说明我们如何收集、使用和保护您的信息。","frontmatter":{"title":"隐私政策","description":"OpenCode 中文教程网站的隐私政策，说明我们如何收集、使用和保护您的信息。"},"headers":[],"relativePath":"privacy.md","filePath":"privacy.md","lastUpdated":1772014034000}'),i={name:"privacy.md"};function t(n,e,s,h,c,d){return o(),r("div",null,[...e[0]||(e[0]=[l('<div class="privacy-page"><h1 id="隐私政策" tabindex="-1">隐私政策 <a class="header-anchor" href="#隐私政策" aria-label="Permalink to “隐私政策”">​</a></h1><p>最后更新：2026 年 1 月</p><p>本隐私政策说明 OpenCode 中文教程（learnopencode.com，以下简称&quot;本站&quot;）如何收集、使用和保护您的信息。</p><h2 id="信息收集" tabindex="-1">信息收集 <a class="header-anchor" href="#信息收集" aria-label="Permalink to “信息收集”">​</a></h2><h3 id="自动收集的信息" tabindex="-1">自动收集的信息 <a class="header-anchor" href="#自动收集的信息" aria-label="Permalink to “自动收集的信息”">​</a></h3><p>当您访问本站时，我们可能通过第三方服务自动收集以下信息：</p><ul><li><strong>设备信息</strong>：浏览器类型、操作系统、屏幕分辨率</li><li><strong>访问信息</strong>：访问时间、页面浏览记录、来源网站</li><li><strong>网络信息</strong>：IP 地址（用于大致地理位置判断）</li></ul><h3 id="cookie-和类似技术" tabindex="-1">Cookie 和类似技术 <a class="header-anchor" href="#cookie-和类似技术" aria-label="Permalink to “Cookie 和类似技术”">​</a></h3><p>本站使用 Cookie 和类似技术来：</p><ul><li>记住您的偏好设置（如深色/浅色主题）</li><li>分析网站流量和使用情况</li><li>展示相关广告</li></ul><h2 id="第三方服务" tabindex="-1">第三方服务 <a class="header-anchor" href="#第三方服务" aria-label="Permalink to “第三方服务”">​</a></h2><p>本站使用以下第三方服务，这些服务有各自的隐私政策：</p><h3 id="google-adsense" tabindex="-1">Google AdSense <a class="header-anchor" href="#google-adsense" aria-label="Permalink to “Google AdSense”">​</a></h3><p>本站使用 Google AdSense 展示广告。Google 可能会使用 Cookie 来展示基于您兴趣的广告。</p><ul><li><a href="https://policies.google.com/technologies/ads" target="_blank" rel="noreferrer">Google 广告隐私政策</a></li><li><a href="https://adssettings.google.com/" target="_blank" rel="noreferrer">如何管理 Google 广告设置</a></li></ul><h3 id="google-analytics-如启用" tabindex="-1">Google Analytics（如启用） <a class="header-anchor" href="#google-analytics-如启用" aria-label="Permalink to “Google Analytics（如启用）”">​</a></h3><p>本站可能使用 Google Analytics 分析网站流量。</p><ul><li><a href="https://policies.google.com/privacy" target="_blank" rel="noreferrer">Google Analytics 隐私政策</a></li></ul><h2 id="广告说明" tabindex="-1">广告说明 <a class="header-anchor" href="#广告说明" aria-label="Permalink to “广告说明”">​</a></h2><p>本站教程内容完全免费。我们通过展示广告来覆盖服务器和域名成本。</p><ul><li>广告由 Google AdSense 提供</li><li>广告内容由 Google 根据您的兴趣自动匹配</li><li>您可以通过 <a href="https://adssettings.google.com/" target="_blank" rel="noreferrer">Google 广告设置</a> 管理个性化广告偏好</li></ul><h2 id="您的选择" tabindex="-1">您的选择 <a class="header-anchor" href="#您的选择" aria-label="Permalink to “您的选择”">​</a></h2><h3 id="管理-cookie" tabindex="-1">管理 Cookie <a class="header-anchor" href="#管理-cookie" aria-label="Permalink to “管理 Cookie”">​</a></h3><p>您可以通过浏览器设置管理或删除 Cookie：</p><ul><li><a href="https://support.google.com/chrome/answer/95647" target="_blank" rel="noreferrer">Chrome Cookie 设置</a></li><li><a href="https://support.mozilla.org/kb/cookies-information-websites-store-on-your-computer" target="_blank" rel="noreferrer">Firefox Cookie 设置</a></li><li><a href="https://support.apple.com/guide/safari/manage-cookies-sfri11471/mac" target="_blank" rel="noreferrer">Safari Cookie 设置</a></li><li><a href="https://support.microsoft.com/microsoft-edge/delete-cookies-in-microsoft-edge-63947406-40ac-c3b8-57b9-2a946a29ae09" target="_blank" rel="noreferrer">Edge Cookie 设置</a></li></ul><h3 id="退出个性化广告" tabindex="-1">退出个性化广告 <a class="header-anchor" href="#退出个性化广告" aria-label="Permalink to “退出个性化广告”">​</a></h3><p>您可以通过以下方式退出个性化广告：</p><ul><li><a href="https://adssettings.google.com/" target="_blank" rel="noreferrer">Google 广告设置</a></li><li><a href="https://optout.networkadvertising.org/" target="_blank" rel="noreferrer">网络广告倡议退出页面</a></li></ul><h2 id="儿童隐私" tabindex="-1">儿童隐私 <a class="header-anchor" href="#儿童隐私" aria-label="Permalink to “儿童隐私”">​</a></h2><p>本站不面向 13 岁以下儿童，我们不会故意收集儿童的个人信息。</p><h2 id="数据安全" tabindex="-1">数据安全 <a class="header-anchor" href="#数据安全" aria-label="Permalink to “数据安全”">​</a></h2><p>我们采取合理的技术和组织措施来保护您的信息安全。但请注意，互联网传输不能保证 100% 安全。</p><h2 id="政策更新" tabindex="-1">政策更新 <a class="header-anchor" href="#政策更新" aria-label="Permalink to “政策更新”">​</a></h2><p>我们可能会不时更新本隐私政策。更新后的政策将在本页面发布，并更新&quot;最后更新&quot;日期。</p><h2 id="联系我们" tabindex="-1">联系我们 <a class="header-anchor" href="#联系我们" aria-label="Permalink to “联系我们”">​</a></h2><p>如果您对本隐私政策有任何疑问，请通过以下方式联系我们：</p><ul><li>GitHub Issues：<a href="https://github.com/vbgate/learn-opencode/issues" target="_blank" rel="noreferrer">https://github.com/vbgate/learn-opencode/issues</a></li><li>微信群：<a href="/community.html">加入社群</a></li></ul><hr></div>',1)])])}const f=a(i,[["render",t]]);export{g as __pageData,f as default};
